// Workflow Dormancy Alerter — compute which expected workflows have gone silent
// past their cadence threshold.
//
// Input: rows from "Get Latest Heartbeats" Postgres node, each
//   { workflow_id, workflow_name, last_seen, silence_seconds }
// Output: single summary item
//   { silent: [...], silent_count, total_expected, checked_at }
//
// Cadence list is hardcoded for v1 (16 workflows). When this exceeds ~30 entries
// or starts changing weekly, lift it to a workflow_cadence_expectations table
// and replace this constant with a SELECT from the Get Latest Heartbeats node's
// preceding query.

const expectations = [
  {
    "workflow_id": "3YahxqOguET3pifj",
    "workflow_name": "Trading - Market Scanner",
    "expected_seconds": 14400,
    "slack": 2
  },
  {
    "workflow_id": "tnvXFYvODL1PrhJa",
    "workflow_name": "Crete - Content Generator",
    "expected_seconds": 86400,
    "slack": 2
  },
  {
    "workflow_id": "9kTWhh9PlxMpyMlp",
    "workflow_name": "Crete - Scheduled Publisher",
    "expected_seconds": 3600,
    "slack": 2
  },
  {
    "workflow_id": "dHceOMijUOcnEowO",
    "workflow_name": "GHL Marketing: Scheduled Publisher",
    "expected_seconds": 900,
    "slack": 2
  },
  {
    "workflow_id": "Awo65rdSe5BvDHtC",
    "workflow_name": "GHL Marketing: Content Generator",
    "expected_seconds": 259200,
    "slack": 2
  },
  {
    "workflow_id": "jRiiOsWneQAtfVPD",
    "workflow_name": "GHL Marketing: Weekly Report",
    "expected_seconds": 604800,
    "slack": 2
  },
  {
    "workflow_id": "kJ2EdkOeEAwVbMwU",
    "workflow_name": "Infographic Social Media V2",
    "expected_seconds": 259200,
    "slack": 2
  },
  {
    "workflow_id": "TikJkWLzpreI6iTa",
    "workflow_name": "Morning Light WL->HL",
    "expected_seconds": 3600,
    "slack": 2
  },
  {
    "workflow_id": "UYA0JppH7eqyI7fQ",
    "workflow_name": "Trading - Position Monitor",
    "expected_seconds": 900,
    "slack": 2
  },
  {
    "workflow_id": "lf955LDteJ512RQi",
    "workflow_name": "Meta Ads Optimisation Agent",
    "expected_seconds": 86400,
    "slack": 2
  },
  {
    "workflow_id": "44g7cbGz5osQ1pcBVhIoz",
    "workflow_name": "Instagram Trial Reels Auto-Publisher",
    "expected_seconds": 18000,
    "slack": 2
  },
  {
    "workflow_id": "yPt090tPv4FJtwAZ",
    "workflow_name": "LinkedIn analytics and monitoring",
    "expected_seconds": 3600,
    "slack": 2
  },
  {
    "workflow_id": "VMqrrhecG2hrpn4C",
    "workflow_name": "LinkedIn Engagement Automation",
    "expected_seconds": 14400,
    "slack": 2
  },
  {
    "workflow_id": "vjj2uBIPc07FpIxx",
    "workflow_name": "Trading - Weekly Analyst",
    "expected_seconds": 604800,
    "slack": 2
  },
  {
    "workflow_id": "cP5TjJ3DFle6r6FC",
    "workflow_name": "Instagram Token Expiry Monitor",
    "expected_seconds": 604800,
    "slack": 2
  },
  {
    "workflow_id": "3XGcnolBQ7AXMubO",
    "workflow_name": "GHL Changelog Emails",
    "expected_seconds": 1209600,
    "slack": 2
  }
];

const heartbeats = $input.all().map(i => i.json);
const heartMap = Object.fromEntries(heartbeats.map(h => [h.workflow_id, h]));

const silent = expectations
  .map(e => {
    const h = heartMap[e.workflow_id];
    if (!h) {
      return {
        workflow_id: e.workflow_id,
        workflow_name: e.workflow_name,
        expected_seconds: e.expected_seconds,
        last_seen: null,
        silence_seconds: null,
        reason: "never_heartbeated",
      };
    }
    const silenceSec = parseInt(h.silence_seconds, 10);
    const threshold = e.expected_seconds * (e.slack || 2);
    if (silenceSec > threshold) {
      return {
        workflow_id: e.workflow_id,
        workflow_name: e.workflow_name || h.workflow_name,
        expected_seconds: e.expected_seconds,
        last_seen: h.last_seen,
        silence_seconds: silenceSec,
        reason: "silent_past_cadence",
      };
    }
    return null;
  })
  .filter(Boolean);

return [{
  json: {
    silent,
    silent_count: silent.length,
    total_expected: expectations.length,
    checked_at: new Date().toISOString(),
  },
}];

parameters.jsonBody:
={{ JSON.stringify({
  chat_id: 1375806243,
  parse_mode: "Markdown",
  text:
    "*Workflow Dormancy Alert*\n" +
    $json.silent_count + " workflow(s) silent past expected cadence (checked " + $json.checked_at.slice(0,16).replace("T"," ") + " UTC):\n\n" +
    $json.silent.map(function(s) {
      var lastSeen = s.last_seen ? new Date(s.last_seen).toISOString().slice(0,16).replace("T"," ") + " UTC" : "never";
      var expSec = s.expected_seconds;
      var expHuman = expSec < 3600 ? Math.round(expSec/60) + "m" : expSec < 86400 ? Math.round(expSec/3600) + "h" : Math.round(expSec/86400) + "d";
      var silenceHuman = s.silence_seconds == null ? "n/a" : (s.silence_seconds < 3600 ? Math.round(s.silence_seconds/60) + "m" : s.silence_seconds < 86400 ? (s.silence_seconds/3600).toFixed(1) + "h" : (s.silence_seconds/86400).toFixed(1) + "d");
      return "• `" + s.workflow_id + "` " + (s.workflow_name || "") + "\n   last: " + lastSeen + " (silence: " + silenceHuman + ", expected every " + expHuman + ")";
    }).join("\n\n")
}) }}
